VALUES
  ('cpa-moex-01601', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '環冠公司於X1年1月1日為興建廠房取得土地（含建物），支付200萬元，且支付50萬元移除 該建物。環冠公司於X1年1月1日隨即與工程公司簽訂興建該廠房合約，工程成本為2000萬元 （X1年1月1日支付500萬元，X1年7月1日支付1000萬元，餘款於完工日支付），預計X2年 2月1日完工。環冠公司X1年之總借款2億元，加權平均利率為10%。該公司經理評估此建案符合 利息資本化條件。試問X1年12月31日止，廠房帳面金額應為何？', '["2000萬元", "1500萬元", "1625萬元", "1600萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01602', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', 'X3年初甲公司以$5,000,000買入高污染性設備，耐用年限為5年，無殘值，採直線法折舊。另根據 法令規定，該設備5年後須委請專業機構予以移除，估計5年後須花$500,000移除處理費，該公司 按折現率10%計提除役負債。甲公司於X7年底，以$480,000請專業機構移除該設備。則甲公司X7年 應認列：', '["$20,000移除利益", "$480,000移除損失", "折舊費用$1,000,000", "折舊費用$1,100,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01603', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '承德公司流通在外普通股（面值$10）50,000股，10%累積完全參加特別股（面值$10）10,000股， 股利積欠一年。本年度已經宣告及發放現金股利$118,000，請問普通股及特別股股東之現金股利各為 多少？', '["特別股股利$30,000；普通股股利$88,000", "特別股股利$29,700；普通股股利$88,300", "特別股股利$28,000；普通股股利$90,000", "特別股股利$36,000；普通股股利$82,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01604', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '企業與員工之股份基礎給付交易（權益交割），應於何時認列所取得之商品或勞務？', '["取得商品或勞務時", "權益商品之給與日", "權益商品之既得日", "權益商品之執行日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01605', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於第1年初向乙租賃公司租用機器一部，租期3年，每年年底支付租金$560,000，甲公司不必 負擔每年約$60,000之機器保險、維修等費用。估計3年租期屆滿時，該機器之殘值為$500,000，租 約規定甲公司得按$50,000 價格承購該機器。該機器於租賃開始日公允價值為$1,174,488，租賃隱含 利率為15%，估計耐用年限為6年，無殘值。按當時承租人增額借款利率12%計算之最低租金給付 額現值為$1,236,504。甲公司於租期屆滿支付承購價款取得該機器之入帳分錄（部分）為：', '["借：應付租賃款       50,000", "借：機器設備           50,000", "借：機器設備        618,252", "貸：租賃資產         1,236,504"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01606', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '大園公司於X1年期初設立，X3年期末因跡象顯示而就一廠房進行減損測試。該廠房為一現金產生 單位，提列折舊後之帳面金額為3000萬元，稅上折舊後之課稅基礎為2200萬元。可回收金額係以 使用價值計算為2400萬元。大園公司適用之營利事業所得稅稅率為25%，減損損失於稅上不能減除。 大園公司減損之會計處理何者正確？', '["借：減損損失450萬元", "借：遞延所得稅負債150萬元", "借：遞延所得稅資產150萬元", "貸：遞延所得稅負債50萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01607', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '中原公司於X1年7月1日出售一部機器設備給大園公司，同時向大園公司租回該機器。X1年7月 1日該機器之帳面金額為$8,500,000，公允價值為$10,000,000，剩餘耐用年限為25年。擬議中租約之 相關主要內容如下：每月$80,000的租金，租期3年，無續約或購回條款，應分類為營業租賃。若最 終協議之出售價格為$9,400,000，且為補償中原公司，每月租金減為$65,000，則中原公司在X1年12月 31日為止的會計年度之損益表應認列出售設備處分損益金額為：', '["$0", "$300,000", "$900,000", "$1,500,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01608', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '甲公司於X6年底時發現，該公司於X4年初購買之設備$560,000，誤列為當年度費用。該公司採直線 法折舊，分9年攤提，殘值為$56,000。若X4、X5年底原列保留盈餘分別為$300,000與$400,000， 不考慮所得稅影響，則將X4年之錯誤更正後，X5及X6年之比較保留盈餘表上，調整後期初保留 盈餘應分別為多少？', '["$356,000；$512,000", "$300,000；$848,000", "$804,000；$848,000", "$804,000；$400,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01609', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '中壢公司於期初設立，期末資產負債表中下列負債項目之課稅基礎計算，何者錯誤？', '["應付薪資：餘額100萬元，於費用認列時稅上列入可減除項目。課稅基礎為100萬元", "應付罰鍰：餘額100萬元，係交通違規罰鍰。課稅基礎為100萬元", "預收租金：餘額100萬元，稅上按權責基礎認列租金收入。課稅基礎為100萬元", "遞延政府捐助收入：餘額100萬元，以收到之補助款購置之資產成本稅上完全可減除，遞延收入 攤銷時列入課稅所得。課稅基礎為100萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01610', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '造成速動比率下降之可能原因為：', '["存貨餘額減少", "預付費用餘額減少", "應收帳款收現", "以低於期初帳面金額之價格出售之交易目的金融資產（分類為流動資產）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01611', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', 'X1年初甲公司以$3,000,000買入高污染放射性設備，耐用年限3年，預計3年後無殘值，採直線法 提列折舊。根據法令規定，該設備3年後須委請專業機構拆卸處理。該公司折現率為10%，估計3年 後須花$100,000拆卸處理費。甲公司於X3年底，以$110,000請專業機構移除該設備，並認列$110,000 處分設備損失。若X3與X4年初甲公司帳列保留盈餘分別為$200,000與$300,000，則X3與X4年初 正確保留盈餘應分別為：', '["$134,134與$300,000", "$149,912與$224,868", "$200,000與$290,000", "$200,000與$300,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01612', 'cpa', 'cpa-moex-101-78566e18', 'sub-cpa-01', NULL, 'single_choice', '八德公司於X1年12年31日按公允價值出售設備予四維公司，同時租回該設備，租期15年。該設 備之相關資料如下： 售價  $480,000 帳面金額  360,000 估計剩餘經濟年限  15年 八德公司X1年損益表認列出售設備利益金額為何？', '["$0", "$8,000", "$112,000", "$120,00"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "a569c7f34429", "answer_pdf_sha1": "66c8fa050463", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "中級會計學", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-01613', 'cpa', 'cpa-moex-101-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '除章程另有規定外，股份有限公司實收資本額未達新臺幣幾億元者，得不發行股票？', '["5億元", "6億元", "7億元", "8億元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:16+00:00", "source_pdf_sha1": "62744a62a0e9", "answer_pdf_sha1": "9e21c8458149", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "803", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公司法、證券交易法與商業會計法", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
